document.addEventListener('DOMContentLoaded', () => {

    // --- 1. Mobile Menu Logic ---
    const mobileMenuBtn = document.getElementById('mobile-menu-btn');
    const mobileMenu = document.getElementById('mobile-menu');

    if (mobileMenuBtn && mobileMenu) {
        // Toggle menu on button click
        mobileMenuBtn.addEventListener('click', () => {
            mobileMenu.classList.toggle('hidden');
        });

        // Close menu automatically when a link is clicked
        mobileMenu.querySelectorAll('a').forEach(link => {
            link.addEventListener('click', () => {
                mobileMenu.classList.add('hidden');
            });
        });
    }

    // --- 2. Rotating Text Animation ---
    const rotatingTextElement = document.getElementById('rotating-text-small');
    if (rotatingTextElement) {
        const phrases = [
            "Sophomore @ UCF",
            "Data Analyst",
            "Analytics Architect",
            "Coffee Lover",
            "Ready to Dive In"
        ];
        let phraseIndex = 0;
        let charIndex = 0;
        let isDeleting = false;
        
        const typingSpeed = 100;
        const deleteSpeed = 50;
        const delayBetweenPhrases = 2000;

        function type() {
            const fullText = phrases[phraseIndex];

            if (isDeleting) {
                rotatingTextElement.textContent = fullText.substring(0, charIndex - 1);
                charIndex--;
            } else {
                rotatingTextElement.textContent = fullText.substring(0, charIndex + 1);
                charIndex++;
            }

            let speed = isDeleting ? deleteSpeed : typingSpeed;

            if (!isDeleting && charIndex === fullText.length) {
                isDeleting = true;
                speed = delayBetweenPhrases;
            } else if (isDeleting && charIndex === 0) {
                isDeleting = false;
                phraseIndex = (phraseIndex + 1) % phrases.length;
                speed = 500;
            }

            setTimeout(type, speed);
        }

        // Only run animation if user hasn't requested reduced motion
        if (!window.matchMedia('(prefers-reduced-motion: reduce)').matches) {
            setTimeout(type, 1000);
        } else {
            rotatingTextElement.textContent = phrases[0];
        }
    }

    // --- 3. Scroll Fade-In Effect ---
    const fadeElements = document.querySelectorAll('.fade-in');
    
    const observerOptions = {
        root: null,
        rootMargin: '0px 0px -50px 0px', 
        threshold: 0.1
    };

    const observer = new IntersectionObserver((entries, observer) => {
        entries.forEach(entry => {
            if (entry.isIntersecting) {
                entry.target.classList.add('is-visible');
                observer.unobserve(entry.target); // Stop observing once visible
            }
        });
    }, observerOptions);

    fadeElements.forEach(el => observer.observe(el));

    // --- 4. Active Navigation Highlight ---
    const navLinks = document.querySelectorAll('.nav-link');
    const sections = document.querySelectorAll('section[id]'); 

    const sectionObserver = new IntersectionObserver((entries) => {
        entries.forEach(entry => {
            if (entry.isIntersecting) {
                const targetId = entry.target.id;
                navLinks.forEach(link => {
                    link.classList.remove('nav-link-active');
                    if (link.getAttribute('href') === `#${targetId}`) {
                        link.classList.add('nav-link-active');
                    }
                });
            }
        });
    }, { rootMargin: '-50% 0px -50% 0px' });

    sections.forEach(section => sectionObserver.observe(section));

    // --- 5. Form Handling (Optional UI Polish) ---
    const form = document.getElementById('contact-form');
    if (form) {
        form.addEventListener('submit', function(e) {
            // Simple check to ensure fields aren't empty before sending
            const name = document.getElementById('name');
            const email = document.getElementById('email');
            
            if (!name.value || !email.value) {
                e.preventDefault();
                alert('Please fill in your name and email!');
            }
        });
    }
});